mod test{
    use super::*;
    use crate::cartridge::test;

    #[test]
    fn test_mem_read_write_to_ram(){
        let mut bus=Bus::new(test::test_rom(vec![]), |_ppu,_joyad|{});
        bus.mem_write(0x01,0x55);
        assert_eq!(bus.mem_read(0x01),0x55);
    }
}

